using System;`nusing System.Collections.Generic;`nusing GestaoManutencao.Core.Domain;`nusing GestaoManutencao.Core.Domain.Equipamentos;`nusing GestaoManutencao.Core.Enums;`nusing GestaoManutencao.Core.Strategies;`nusing GestaoManutencao.Core.Exceptions;`n`nnamespace GestaoManutencao.App`n{`n    class Program`n    {`n        static void Main(string[] sender)`n        {`n            Console.WriteLine("=== SISTEMA DE GESTAO DE MANUTENCAO ===");`n            Console.WriteLine("--- Executando Demonstracao Impecavel das Regras de Negocio ---\n");`n`n            // 1. Criando Clientes (Um com contrato e outro sem)`n            var clienteComercial = new Cliente("Supermercado Alvorada", TipoClienteComercial);`n            var contrato = new ContratoManutencao(15.00m, Prioridade.Alta); // 15% de desconto e prioridade mínima Alta`n            clienteComercial.VincularContrato(contrato);`n`n            var clienteResidencial = new Cliente("Carlos Silva", TipoCliente.Residencial);`n`n            // 2. Criando Equipamentos vinculados aos donos corretos`n            var arCondicionado = new EquipamentoRefrigeracao("Ar Condicionado Central VRF", "Carrier", clienteComercial, "R-410A");`n            var tvEletronica = new DispositivoEletronico("Smart TV 65 Pol", "Samsung", clienteResidencial, "v1.4.2");`n`n            // 3. Cadastrando Técnicos com suas respectivas especialidades`n            var tecnicoFrio = new Tecnico("Roberto Especialista em Refrigeraçăo", new List<EspecialidadeTecnica> { EspecialidadeTecnica.Refrigeracao });`n            var tecnicoGeral = new Tecnico("Amanda Polivalente", new List<EspecialidadeTecnica> { EspecialidadeTecnica.Eletrica, EspecialidadeTecnica.Eletronica });`n`n            // 4. Definindo as Estratégias que serăo usadas no fluxo`n            var estrategiaPrioridadeContrato = new PriorizacaoComContrato();`n            var estrategiaPrecoContrato = new CalculoComDescontoContrato();`n`n            Console.WriteLine(">>> CASO 1: FLUXO PERFEITO COM CLIENTE COM CONTRATO <<<");`n            // Criando solicitaçăo: Note que a prioridade mínima será dita pelo contrato (Alta)`n            var solicitacao1 = new SolicitacaoManutencao("Vazamento de agua na evaporadora principal", NivelUrgencia.Medio, clienteComercial, arCondicionado, estrategiaPrioridadeContrato);`n            Console.WriteLine($"Chamado Aberto com Sucesso! Estado Atual: {solicitacao1.EstadoAtual.Nome}");`n            Console.WriteLine($"Prioridade Calculada Automaticamente: {solicitacao1.Prioridade}");`n`n            // Atribuindo o técnico compatível (Refrigeraçăo para Equipamento de Refrigeraçăo)`n            solicitacao1.AtribuirTecnico(tecnicoFrio);`n            Console.WriteLine($"Tecnico {solicitacao1.TecnicoResponsavel.Nome} atribuido! Novo Estado: {solicitacao1.EstadoAtual.Nome}");`n`n            // Adicionando os serviços realizados`n            solicitacao1.AdicionarServico(new ServicoRealizado("Troca de valvula de expansao", 2.5, 120.00m));`n            solicitacao1.AdicionarServico(new ServicoRealizado("Carga de gas refrigerante", 1.0, 250.00m));`n            Console.WriteLine($"Quantidade de servicos registrados: {solicitacao1.Servicos.Count}");`n`n            // Calculando valor total aplicando a estratégia de desconto contratual`n            decimal custoFinal1 = solicitacao1.CalcularCustoTotal(estrategiaPrecoContrato);`n            Console.WriteLine($"Custo Total Calculado (Com 15% de Desconto do Contrato): R$ {custoFinal1:F2}");`n`n            // Avançando para concluir o chamado`n            solicitacao1.AvancarEstado();`n            Console.WriteLine($"Estado Final da Solicitacao: {solicitacao1.EstadoAtual.Nome}\n");`n`n            Console.WriteLine(">>> CASO 2: DEMONSTRACAO DE PROTECAO DE INVARIANTES (TESTE DE ERROS) <<<");`n            `n            // Teste de Erro A: Tentar atribuir um técnico sem a especialidade requerida pelo equipamento`n            try`n            {`n                Console.WriteLine("Tentando atribuir tecnico de Eletronica para consertar o Ar Condicionado...");`n                var solicitacaoErro = new SolicitacaoManutencao("Manutencao preventiva no compressor", NivelUrgencia.Baixo, clienteComercial, arCondicionado, estrategiaPrioridadeContrato);`n                solicitacaoErro.AtribuirTecnico(tecnicoGeral);`n            }`n            catch (TecnicoIncompativelException ex)`n            {`n                Console.WriteLine($"[BLOQUEADO PELO SISTEMA]: {ex.Message}");`n            }`n`n            // Teste de Erro B: Tentar injetar novos serviços em um chamado que já foi Finalizado`n            try`n            {`n                Console.WriteLine("\nTentando adicionar um servico extra na Solicitacao 1 que ja foi Finalizada...");`n                solicitacao1.AdicionarServico(new ServicoRealizado("Limpeza de filtros residual", 1.0, 50.00m));`n            }`n            catch (TransicaoEstadoInvalidaException ex)`n            {`n                Console.WriteLine($"[BLOQUEADO PELO SISTEMA]: {ex.Message}");`n            }`n`n            Console.WriteLine("\n=== FIM DA DEMONSTRACAO: SISTEMA TOTALMENTE SEGURO ===");`n        }`n    }`n}
